(()=>{const $=(root,sel)=>root.querySelector(sel);const words=s=>(s.trim().match(/\b[\p{L}\p{N}'-]+\b/gu)||[]);
  const sentences=s=>(s.match(/[^.!?]+[.!?]+|[^.!?]+$/g)||[]).filter(x=>x.trim());
  const paras=s=>s.split(/\n\s*\n/).filter(x=>x.trim());
  const lines=s=>s.split(/\r?\n/);
  const esc=s=>s.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
  const titleSmall=new Set('a an and as at but by for in nor of on or per the to vs via with'.split(''));
  function toTitle(s){return s.toLowerCase().replace(/\b[\p{L}\p{N}'-]+\b/gu,(w,i)=>i>0&&titleSmall.has(w)?w:w.charAt(0).toUpperCase()+w.slice(1));}function wordsForCase(s){return s.normalize('NFKD').replace(/[\u0300-\u036f]/g,'').match(/[A-Za-z0-9]+/g)||[];}function slug(s){return s.normalize('NFKD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/&/g,' and ').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').replace(/-{2,}/g,'-');}function stats(s){const l=lines(s);const w=words(s);return{Characters:s.length,'Characters no spaces':s.replace(/\s/g,'').length,Words:w.length,Sentences:sentences(s).length,Paragraphs:paras(s).length,Lines:l.length,'Non-empty lines':l.filter(x=>x.trim()).length,'Reading time':Math.max(1,Math.ceil(w.length/225))+' min'};}function renderStats(root,obj){const box=$(root,'[data-stats]');box.innerHTML=Object.entries(obj).map(([k,v])=>`<div><strong>${v}</strong><span>${k}</span></div>`).join('');}function process(root){const mode=root.dataset.textMode;const input=$(root,'[data-text-input]').value;let output=input;let st=stats(input);if(mode==='word-counter'||mode==='character-counter'||mode==='line-counter'){if(mode==='line-counter'){const l=lines(input);const non=l.filter(x=>x.trim());st={Lines:l.length,'Non-empty lines':non.length,'Empty lines':l.length-non.length,'Longest line':l.reduce((m,x)=>Math.max(m,x.length),0),'Average line length':l.length?Math.round(l.reduce((a,x)=>a+x.length,0)/l.length):0};}output=input;}else if(mode==='case-converter'){const style=$(root,'[data-case-style]').value;const ws=wordsForCase(input);output=style==='upper'?input.toUpperCase():style==='lower'?input.toLowerCase():style==='sentence'?input.toLowerCase().replace(/(^\s*\p{L}|[.!?]\s*\p{L})/gu,m=>m.toUpperCase()):style==='title'?toTitle(input):style==='camel'?ws.map((w,i)=>i?w[0].toUpperCase()+w.slice(1).toLowerCase():w.toLowerCase()).join(''):style==='pascal'?ws.map(w=>w[0].toUpperCase()+w.slice(1).toLowerCase()).join(''):style==='snake'?ws.map(w=>w.toLowerCase()).join('_'):ws.map(w=>w.toLowerCase()).join('-');}else if(mode==='title-case')output=toTitle(input);else if(mode==='dedupe-lines'){const ignore=$(root,'[data-ignore-case]').checked;const seen=new Set();let out=[];for(const line of lines(input)){const key=ignore?line.toLowerCase():line;if(!seen.has(key)){seen.add(key);out.push(line);}}if($(root,'[data-sort-unique]').checked)out.sort((a,b)=>a.localeCompare(b));output=out.join('\n');st['Removed duplicates']=lines(input).length-out.length;}else if(mode==='sort-lines'){const modeSort=$(root,'[data-sort-mode]').value;const ignore=$(root,'[data-ignore-case]')?.checked;const arr=lines(input);arr.sort((a,b)=>modeSort==='numeric'?(parseFloat(a)||0)-(parseFloat(b)||0):modeSort==='length'?a.length-b.length:(ignore?a.toLowerCase():a).localeCompare(ignore?b.toLowerCase():b));if(modeSort==='za')arr.reverse();output=arr.join('\n');}else if(mode==='remove-empty')output=lines(input).map(x=>x.trim()).filter(Boolean).join('\n');else if(mode==='slug')output=slug(input);else if(mode==='find-replace'){const find=$(root,'[data-find]').value,rep=$(root,'[data-replace]').value,flags=$(root,'[data-ignore-case]').checked?'gi':'g';if(find){try{const re=$(root,'[data-regex]').checked?new RegExp(find,flags):new RegExp(esc(find),flags);output=input.replace(re,rep);}catch(e){$(root,'[data-status]').textContent='Invalid regular expression: '+e.message;return;}}}$(root,'[data-text-output]').value=output;renderStats(root,st);$(root,'[data-status]').textContent=`Processed ${input.length.toLocaleString()} characters into ${output.length.toLocaleString()} characters.`;}document.addEventListener('input',e=>{const root=e.target.closest('.text-tool');if(root)process(root);});document.addEventListener('click',e=>{const root=e.target.closest('.text-tool');if(!root)return;if(e.target.matches('[data-text-run]'))process(root);if(e.target.matches('[data-copy]'))navigator.clipboard.writeText($(root,'[data-text-output]').value).then(()=>$(root,'[data-status]').textContent='Copied output to clipboard.');if(e.target.matches('[data-download-text]')){const blob=new Blob([$(root,'[data-text-output]').value],{type:'text/plain'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`pawstool-${root.dataset.toolSlug||'text'}.txt`;a.click();}if(e.target.matches('[data-clear]')){$(root,'[data-text-input]').value='';$(root,'[data-text-output]').value='';$(root,'[data-stats]').innerHTML='';$(root,'[data-status]').textContent='Cleared. Paste text to begin.';}});document.querySelectorAll('.text-tool').forEach(process);})();